import{_ as e,o as n,c as s,a2 as o}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Integracion con DDD y arquitectura hexagonal","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/clean-architecture/09-integracion-con-ddd-y-hexagonal.md","filePath":"full-stack/arquitectura/clean-architecture/09-integracion-con-ddd-y-hexagonal.md","lastUpdated":1782521464000}'),t={name:"full-stack/arquitectura/clean-architecture/09-integracion-con-ddd-y-hexagonal.md"};function r(i,a,l,p,c,d){return n(),s("div",null,[...a[0]||(a[0]=[o(`<h1 id="integracion-con-ddd-y-arquitectura-hexagonal" tabindex="-1">Integracion con DDD y arquitectura hexagonal <a class="header-anchor" href="#integracion-con-ddd-y-arquitectura-hexagonal" aria-label="Permalink to &quot;Integracion con DDD y arquitectura hexagonal&quot;">​</a></h1><p>Clean Architecture, DDD y arquitectura hexagonal no son enemigos. Suelen encajar muy bien.</p><h2 id="relacion-entre-enfoques" tabindex="-1">Relacion entre enfoques <a class="header-anchor" href="#relacion-entre-enfoques" aria-label="Permalink to &quot;Relacion entre enfoques&quot;">​</a></h2><ul><li>DDD ayuda a modelar el negocio.</li><li>Hexagonal ayuda a aislar puertos y adaptadores.</li><li>Clean Architecture ayuda a ordenar dependencias por capas.</li></ul><h2 id="mapa-mental" tabindex="-1">Mapa mental <a class="header-anchor" href="#mapa-mental" aria-label="Permalink to &quot;Mapa mental&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DDD:</span></span>
<span class="line"><span>  entidades, value objects, agregados, bounded contexts</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Hexagonal:</span></span>
<span class="line"><span>  puertos de entrada, puertos de salida, adaptadores</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Clean Architecture:</span></span>
<span class="line"><span>  dominio, aplicacion, infraestructura, presentacion</span></span></code></pre></div><h2 id="ejemplo-de-combinacion" tabindex="-1">Ejemplo de combinacion <a class="header-anchor" href="#ejemplo-de-combinacion" aria-label="Permalink to &quot;Ejemplo de combinacion&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>orders/</span></span>
<span class="line"><span>  domain/</span></span>
<span class="line"><span>    Order</span></span>
<span class="line"><span>    OrderLine</span></span>
<span class="line"><span>    Money</span></span>
<span class="line"><span>  application/</span></span>
<span class="line"><span>    ConfirmOrderUseCase</span></span>
<span class="line"><span>    OrderRepository</span></span>
<span class="line"><span>    PaymentGateway</span></span>
<span class="line"><span>  infrastructure/</span></span>
<span class="line"><span>    PostgresOrderRepository</span></span>
<span class="line"><span>    StripePaymentGateway</span></span>
<span class="line"><span>  presentation/</span></span>
<span class="line"><span>    OrderController</span></span></code></pre></div><p>DDD da sentido al modelo. Hexagonal marca los puertos. Clean Architecture ordena la dependencia.</p><h2 id="cuando-usar-ddd" tabindex="-1">Cuando usar DDD <a class="header-anchor" href="#cuando-usar-ddd" aria-label="Permalink to &quot;Cuando usar DDD&quot;">​</a></h2><p>DDD aporta valor cuando el negocio tiene reglas complejas, hay conversaciones frecuentes con personas de negocio o el sistema no es solo CRUD.</p><h2 id="cuando-usar-hexagonal" tabindex="-1">Cuando usar hexagonal <a class="header-anchor" href="#cuando-usar-hexagonal" aria-label="Permalink to &quot;Cuando usar hexagonal&quot;">​</a></h2><p>Hexagonal es especialmente util cuando hay varias formas de entrada, varias integraciones externas o necesitas tests aislados de adaptadores.</p><h2 id="error-comun" tabindex="-1">Error comun <a class="header-anchor" href="#error-comun" aria-label="Permalink to &quot;Error comun&quot;">​</a></h2><p>Pensar que hay que aplicar todos los patrones a la vez. Puedes empezar con casos de uso y repositorios, despues introducir value objects, luego eventos y finalmente bounded contexts si el sistema lo pide.</p>`,15)])])}const m=e(t,[["render",r]]);export{h as __pageData,m as default};
